import { authApi } from '@/lib/services/api-client'
import NextAuth from 'next-auth'
import CredentialsProvider from 'next-auth/providers/credentials'

const handler = NextAuth({
  secret: process.env.NEXTAUTH_SECRET,
  providers: [
    CredentialsProvider({
      name: 'credentials',
      credentials: {
        email: { label: 'Email', type: 'email' },
        password: { label: 'Password', type: 'password' }
      },
      async authorize(credentials) {
        console.log('🔐 NextAuth authorize called with:', { 
          email: credentials?.email,
          hasPassword: !!credentials?.password 
        });

        try {
          console.log('📡 Calling backend API:', `${process.env.NEXT_PUBLIC_API_URL}/auth/login`);
          
          const data = await authApi.login({
            email: credentials?.email || '',
            password: credentials?.password || '',
          })

          console.log('✅ Backend response:', { 
            userId: data.user.id,
            email: data.user.email,
            hasToken: !!data.token 
          });

          if (data.token) {
            const user = {
              id: data.user.id,
              email: data.user.email,
              name: `${data.user.firstName} ${data.user.lastName}`,
              firstName: data.user.firstName,
              lastName: data.user.lastName,
              userType: data.user.userType,
              accessToken: data.token,
            }
            
            console.log('👤 User object created:', user);
            return user as any;
          }

          console.log('❌ No token in response');
          return null;
        } catch (error: any) {
          console.error('🚨 Auth error:', {
            message: error.message,
            status: error.response?.status,
            data: error.response?.data,
            stack: error.stack
          });

          if (error.response?.status === 401) {
            throw new Error('Invalid email or password');
          } else if (error.response?.status === 400) {
            throw new Error(error.response?.data?.message || 'Invalid request');
          } else if (error.response?.status >= 500) {
            throw new Error('Authentication service is temporarily unavailable');
          } else {
            throw new Error('Authentication failed. Please try again.');
          }
        }
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      console.log('🪙 JWT callback:', { tokenSub: token.sub, userEmail: user?.email });
      if (user) {
        token.accessToken = (user as any).accessToken
        token.user = {
          id: user.id,
          firstName: (user as any).firstName,
          lastName: (user as any).lastName,
          userName: (user as any).userName,
          email: user.email!,
          userType: (user as any).userType,
        }
      }
      return token
    },
    async session({ session, token }) {
      console.log('💼 Session callback:', { sessionUser: session.user?.email, tokenUser: token.user?.email });
      session.accessToken = token.accessToken as string
      session.user = token.user as any
      return session
    },
  },
  pages: {
    signIn: '/login',
    error: '/login',
  },
  session: {
    strategy: 'jwt',
    maxAge: 30 * 24 * 60 * 60,
  },
  debug: process.env.NODE_ENV === 'development', // Enable NextAuth debug mode
})

export { handler as GET, handler as POST }